--
-- Table structure for table `receipt_settings`
--

DROP TABLE IF EXISTS `receipt_settings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `receipt_settings` (
  `id` int NOT NULL AUTO_INCREMENT,
  `business_id` int DEFAULT NULL COMMENT 'NULL = global settings, INT = business-specific settings',
  `store_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Store name (e.g., "MOMOYO")',
  `address` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Store address',
  `phone_number` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Contact phone number',
  `contact_phone` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Alternative contact phone (e.g., "silahkan hubungi: 0813-9888-8568")',
  `logo_base64` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Logo as base64 data URI',
  `footer_text` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Footer text on receipt',
  `partnership_contact` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Partnership contact info',
  `is_active` tinyint(1) DEFAULT '1' COMMENT 'Whether these settings are active',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
