--
-- Table structure for table `shifts`
--

DROP TABLE IF EXISTS `shifts`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `shifts` (
  `id` int NOT NULL AUTO_INCREMENT,
  `uuid_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `business_id` int NOT NULL,
  `user_id` int NOT NULL,
  `user_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `shift_start` datetime NOT NULL,
  `shift_end` datetime DEFAULT NULL,
  `modal_awal` decimal(15,2) DEFAULT '0.00',
  `kas_akhir` decimal(15,2) DEFAULT NULL,
  `kas_expected` decimal(15,2) DEFAULT NULL,
  `kas_selisih` decimal(15,2) DEFAULT NULL,
  `kas_selisih_label` enum('balanced','plus','minus') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'balanced',
  `cash_sales_total` decimal(15,2) DEFAULT NULL,
  `cash_refund_total` decimal(15,2) DEFAULT NULL,
  `status` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT 'active',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` bigint DEFAULT NULL,
  `synced_at` bigint DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_shifts_uuid` (`uuid_id`),
  KEY `idx_shifts_business_user` (`business_id`,`user_id`),
  KEY `idx_shifts_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=1432 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

