--
-- Table structure for table `transaction_items`
--

DROP TABLE IF EXISTS `transaction_items`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `transaction_items` (
  `id` int NOT NULL AUTO_INCREMENT,
  `uuid_id` varchar(36) NOT NULL,
  `transaction_id` int NOT NULL,
  `uuid_transaction_id` varchar(36) NOT NULL,
  `product_id` int NOT NULL,
  `quantity` int NOT NULL DEFAULT '1',
  `unit_price` decimal(15,2) NOT NULL,
  `total_price` decimal(15,2) NOT NULL,
  `custom_note` text COMMENT 'Custom note or special instructions for this item',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `cancelled_by_user_id` int DEFAULT NULL COMMENT 'User who authorized the cancellation',
  `cancelled_by_waiter_id` int DEFAULT NULL COMMENT 'Waiter who performed the cancellation via PIN',
  `waiter_id` int DEFAULT NULL,
  `bundle_selections_json` json DEFAULT NULL COMMENT 'JSON array storing selected products for bundle items',
  `package_selections_json` text,
  `production_started_at` timestamp NULL DEFAULT NULL COMMENT 'Timestamp when production started (item appeared in kitchen/barista display)',
  `production_status` enum('preparing','finished','cancelled') DEFAULT NULL,
  `production_finished_at` timestamp NULL DEFAULT NULL COMMENT 'Timestamp when production finished (item marked as ready)',
  `cancelled_at` timestamp NULL DEFAULT NULL COMMENT 'When this item was cancelled (NULL if not cancelled)',
  `package_line_finished_at_json` text COMMENT 'Per-line finished-at times for package breakdown (JSON: {"0":"iso",...})',
  `rental_duration_value` decimal(10,2) DEFAULT NULL COMMENT 'Structured rental duration amount',
  `rental_duration_unit` enum('hour','day','month') DEFAULT NULL COMMENT 'Unit for rental_duration_value',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uuid_id` (`uuid_id`),
  KEY `idx_transaction_items_transaction` (`transaction_id`),
  KEY `idx_transaction_items_product` (`product_id`),
  KEY `idx_transaction_items_created` (`created_at`),
  KEY `fk_transaction_items_transaction_uuid` (`uuid_transaction_id`),
  KEY `idx_transaction_items_production_status` (`production_status`),
  KEY `idx_transaction_items_transaction_created` (`transaction_id`,`id`),
  KEY `idx_transaction_items_cancelled_at` (`cancelled_at`),
  KEY `idx_transaction_items_cancelled_by_user` (`cancelled_by_user_id`),
  KEY `idx_transaction_items_cancelled_by_waiter` (`cancelled_by_waiter_id`),
  KEY `idx_transaction_items_rental_duration` (`rental_duration_unit`,`rental_duration_value`),
  CONSTRAINT `fk_transaction_items_transaction_uuid` FOREIGN KEY (`uuid_transaction_id`) REFERENCES `transactions` (`uuid_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=76909 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='Individual items within each transaction';
/*!40101 SET character_set_client = @saved_cs_client */;

