--
-- Table structure for table `transactions`
--

DROP TABLE IF EXISTS `transactions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `transactions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `uuid_id` varchar(36) NOT NULL,
  `business_id` int NOT NULL,
  `user_id` int NOT NULL,
  `waiter_id` int DEFAULT NULL,
  `shift_uuid` char(36) DEFAULT NULL,
  `payment_method` varchar(50) NOT NULL,
  `pickup_method` enum('dine-in','take-away') NOT NULL,
  `total_amount` decimal(15,2) NOT NULL,
  `voucher_discount` decimal(15,2) DEFAULT '0.00' COMMENT 'Voucher discount amount',
  `voucher_type` enum('none','percent','nominal','free') DEFAULT 'none',
  `voucher_value` decimal(15,2) DEFAULT NULL,
  `voucher_label` varchar(255) DEFAULT NULL,
  `final_amount` decimal(15,2) NOT NULL COMMENT 'Final amount after voucher discount',
  `mdr_rate_percent` decimal(8,4) DEFAULT NULL COMMENT 'QR/QRIS MDR %% snapshot at payment time',
  `mdr_amount` decimal(15,2) DEFAULT NULL COMMENT 'QR/QRIS MDR fee amount',
  `net_after_mdr` decimal(15,2) DEFAULT NULL COMMENT 'Expected net settlement after MDR',
  `amount_received` decimal(15,2) NOT NULL,
  `change_amount` decimal(15,2) DEFAULT '0.00',
  `status` enum('pending','completed','cancelled','refunded') DEFAULT 'completed',
  `refund_status` enum('none','partial','full') NOT NULL DEFAULT 'none',
  `refund_total` decimal(15,2) NOT NULL DEFAULT '0.00',
  `last_refunded_at` datetime DEFAULT NULL,
  `system_pos_synced_at` datetime DEFAULT NULL COMMENT 'When refund data was last synced from main DB',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `paid_at` datetime DEFAULT NULL COMMENT 'When the transaction was paid',
  `contact_id` int DEFAULT NULL COMMENT 'Reference to contact book entry',
  `customer_name` varchar(255) DEFAULT NULL COMMENT 'Customer name (manual entry)',
  `customer_unit` int DEFAULT NULL COMMENT 'Number of customers in the party',
  `caller_number` int DEFAULT NULL COMMENT 'Wireless caller/pager number (1-50)',
  `note` text COMMENT 'Additional notes or comments for the transaction',
  `bank_name` varchar(100) DEFAULT NULL COMMENT 'Bank name for debit payments',
  `card_number` varchar(20) DEFAULT NULL COMMENT 'Card number for debit payments',
  `cl_account_id` int DEFAULT NULL COMMENT 'Reference to CL account',
  `cl_account_name` varchar(100) DEFAULT NULL COMMENT 'CL account name for quick reference',
  `bank_id` int DEFAULT NULL COMMENT 'Reference to banks table',
  `receipt_number` int DEFAULT NULL COMMENT 'Daily receipt number, resets each day',
  `transaction_type` enum('drinks','bakery') DEFAULT 'drinks' COMMENT 'Type of transaction: drinks or bakery',
  `payment_method_id` int NOT NULL,
  `sync_status` enum('pending','synced','failed') DEFAULT 'pending',
  `sync_attempts` int DEFAULT '0',
  `synced_at` datetime DEFAULT NULL,
  `last_sync_attempt` timestamp NULL DEFAULT NULL,
  `last_sync_error` varchar(512) DEFAULT NULL COMMENT 'Last sync failure reason',
  `table_id` int DEFAULT NULL,
  `checker_printed` tinyint(1) NOT NULL DEFAULT '0' COMMENT '1 = kitchen labels/checker already printed',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uuid_id` (`uuid_id`),
  KEY `idx_transactions_business` (`business_id`),
  KEY `idx_transactions_user` (`user_id`),
