  KEY `idx_transactions_sync_status` (`sync_status`),
  KEY `idx_transactions_user_business_date_status` (`user_id`,`business_id`,`created_at`,`status`),
  KEY `idx_transactions_user_business_date_payment_status` (`user_id`,`business_id`,`created_at`,`payment_method_id`,`status`),
  KEY `idx_transactions_table_status` (`table_id`,`status`),
  KEY `idx_transactions_waiter` (`waiter_id`),
  CONSTRAINT `fk_transactions_business` FOREIGN KEY (`business_id`) REFERENCES `businesses` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_transactions_payment_method` FOREIGN KEY (`payment_method_id`) REFERENCES `payment_methods` (`id`),
  CONSTRAINT `fk_transactions_table` FOREIGN KEY (`table_id`) REFERENCES `restaurant_tables` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_transactions_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_transactions_waiter` FOREIGN KEY (`waiter_id`) REFERENCES `employees` (`id`) ON DELETE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=22484 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='POS Transaction records';
